 */
public object FfiConverterTypeChatEventCallback: FfiConverter<ChatEventCallback, Long> {
    internal val handleMap = UniffiHandleMap<ChatEventCallback>()

    override fun lower(value: ChatEventCallback): Long {
        if (value is ChatEventCallbackImpl) {
             // Rust-implemented object.  Clone the handle and return it
            return value.uniffiCloneHandle()
         } else {
            // Kotlin object, generate a new vtable handle and return that.
            return handleMap.insert(value)
         }
    }

    override fun lift(value: Long): ChatEventCallback {
        if ((value and 1.toLong()) == 0.toLong()) {
            // Rust-generated handle, construct a new class that uses the handle to implement the
            // interface
            return ChatEventCallbackImpl(UniffiWithHandle, value)
        } else {
            // Kotlin-generated handle, get the object from the handle map
            return handleMap.remove(value)
        }
    }

    override fun read(buf: ByteBuffer): ChatEventCallback {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: ChatEventCallback) = 8UL

    override fun write(value: ChatEventCallback, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}


