    /**
     * Use the deny-all interaction gate (every point aborted).
     */
    fun `denyAllInteractionGate`(): OneAiAppBuilder
    
    /**
     * Set the memory manager with custom config.
     */
    fun `memoryManagerWithConfig`(`thresholdTokens`: kotlin.UInt): OneAiAppBuilder
    
    /**
     * Use the no-op interaction gate (every point disabled, zero latency).
     */
    fun `noopInteractionGate`(): OneAiAppBuilder
    
    /**
     * Set the persistence layer.
     */
    fun `persistence`(`path`: kotlin.String): OneAiAppBuilder
    
    /**
