/**
 * Approval request (UniFFI-compatible view).
 *
 * `args_json` is a JSON-encoded string of the tool arguments,
 * since `serde_json::Value` cannot be exported via UniFFI.
 */
data class ApprovalRequestView (
    /**
     * The name of the tool requesting approval.
     */
    var `toolName`: kotlin.String
    , 
    /**
     * JSON-encoded tool arguments.
     */
    var `argsJson`: kotlin.String
    , 
    /**
     * The risk level classification.
     */
    var `riskLevel`: RiskLevelView
    , 
    /**
     * The permission level classification (optional — replaces risk_level).
     */
    var `permissionLevel`: PermissionLevelView?
    , 
    /**
     * Justification for why the tool should be allowed.
     */
    var `justification`: kotlin.String
    
){
    

    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeApprovalRequestView: FfiConverterRustBuffer<ApprovalRequestView> {
    override fun read(buf: ByteBuffer): ApprovalRequestView {
        return ApprovalRequestView(
            FfiConverterString.read(buf),
            FfiConverterString.read(buf),
            FfiConverterTypeRiskLevelView.read(buf),
            FfiConverterOptionalTypePermissionLevelView.read(buf),
            FfiConverterString.read(buf),
        )
    }

    override fun allocationSize(value: ApprovalRequestView) = (
            FfiConverterString.allocationSize(value.`toolName`) +
            FfiConverterString.allocationSize(value.`argsJson`) +
            FfiConverterTypeRiskLevelView.allocationSize(value.`riskLevel`) +
            FfiConverterOptionalTypePermissionLevelView.allocationSize(value.`permissionLevel`) +
            FfiConverterString.allocationSize(value.`justification`)
    )

    override fun write(value: ApprovalRequestView, buf: ByteBuffer) {
            FfiConverterString.write(value.`toolName`, buf)
            FfiConverterString.write(value.`argsJson`, buf)
            FfiConverterTypeRiskLevelView.write(value.`riskLevel`, buf)
            FfiConverterOptionalTypePermissionLevelView.write(value.`permissionLevel`, buf)
            FfiConverterString.write(value.`justification`, buf)
    }
}



/**
 * A single conversation message (UniFFI-compatible view).
 *
 * Flattened to `role` + `text` — multimodal content blocks are reduced to
 * their text content via `Message::text_content()`. Returned by
 * `OneAISession::messages()` so a foreign UI can replay a resumed
 * conversation's history. `role` is one of `"system"`, `"user"`,
 * `"assistant"`, `"tool"`.
 */
data class MessageView (
    /**
     * Author role: `"system"` / `"user"` / `"assistant"` / `"tool"`.
     */
    var `role`: kotlin.String
    , 
    /**
     * Concatenated text content of the message's text blocks.
     */
    var `text`: kotlin.String
    
){
    

    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeMessageView: FfiConverterRustBuffer<MessageView> {
    override fun read(buf: ByteBuffer): MessageView {
        return MessageView(
            FfiConverterString.read(buf),
            FfiConverterString.read(buf),
        )
    }

    override fun allocationSize(value: MessageView) = (
            FfiConverterString.allocationSize(value.`role`) +
            FfiConverterString.allocationSize(value.`text`)
    )

    override fun write(value: MessageView, buf: ByteBuffer) {
            FfiConverterString.write(value.`role`, buf)
            FfiConverterString.write(value.`text`, buf)
    }
}



/**
 * Provider configuration for foreign-language App construction.
 *
 * Passed to `OneAIAppBuilder::provider_config` so foreign code can build an
 * LLM-backed app without handling `Arc<dyn LlmProvider>` (which UniFFI can't
 * cross). `kind` selects the concrete provider constructed on the Rust side;
 * the remaining fields are forwarded to that provider's `ModelConfig`.
 */
data class ProviderConfigView (
    /**
     * Provider kind: `"openai"`, `"anthropic"`, or `"ollama"`.
     */
    var `kind`: kotlin.String
    , 
    /**
     * API key (required for openai/anthropic; ignored for ollama).
     */
    var `apiKey`: kotlin.String?
    , 
    /**
     * Base URL override (OpenAI-compatible endpoints). `None` = provider default.
     */
    var `baseUrl`: kotlin.String?
    , 
    /**
     * Model name (e.g. `gpt-4o`, `claude-sonnet-4`, `llama3`).
     */
    var `model`: kotlin.String
    , 
    /**
     * Ollama host (ollama only). `None` = `http://localhost`.
     */
    var `host`: kotlin.String?
    , 
    /**
     * Ollama port (ollama only). `None` = 11434.
     */
    var `port`: kotlin.UShort?
    
){
    

    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeProviderConfigView: FfiConverterRustBuffer<ProviderConfigView> {
    override fun read(buf: ByteBuffer): ProviderConfigView {
        return ProviderConfigView(
