     */
    READ,
    /**
     * Standard — common operations. May require approval.
     */
    STANDARD,
    /**
     * Full — powerful operations. Always requires approval.
     */
    FULL;

    


    companion object
}


/**
 * @suppress
 */
public object FfiConverterTypePermissionLevelView: FfiConverterRustBuffer<PermissionLevelView> {
    override fun read(buf: ByteBuffer) = try {
        PermissionLevelView.values()[buf.getInt() - 1]
    } catch (e: IndexOutOfBoundsException) {
        throw RuntimeException("invalid enum value, something is very wrong!!", e)
    }

    override fun allocationSize(value: PermissionLevelView) = 4UL

    override fun write(value: PermissionLevelView, buf: ByteBuffer) {
        buf.putInt(value.ordinal + 1)
    }
}





